#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.credits)]
    public class CreditsOptionButton : OptionButtonDefinition
    {
        public CreditsOptionButton(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return context is not IOptionContextLevel;
        }
        public override void OnClick()
        {
            Global.Scene.OpenCreditsPanel();
        }
    }
}
